        if (winner != ' ') {
            break;
        }

        //get player input
        cout << "Current Player is " << currentPlayer << endl;
        while (true) {
            cout << "Enter r c from 0-2 for row and column: ";
            cin >> r >> c;
            if (r < 0 || r > 2 || c < 0 || c > 2) {
                cout << "Invalid input, try again." << endl;
            }
            else if (board[r][c] != ' ') {
                cout << "Tile is full, try again." << endl;
            }
            else {
                break;
            }
            //reset values
